console.info('Welcome to the Test Runner!');
describe('Calculator', () => {
  
  describe('add', () => {
    it('should return the sum of two numbers', () => {
      const result = add(2, 3);
      assert.strictEqual(result, 5);
    });

    it('should return the sum of negative numbers', () => {
      const result = add(-2, -3);
      assert.strictEqual(result, -5);
    });
  });

  describe('subtract', () => {
    it('should return the difference of two numbers', () => {
      const result = subtract(5, 3);
      assert.strictEqual(result, 2);
    });

    it('should return a negative difference if the first number is smaller', () => {
      const result = subtract(3, 5);
      assert.strictEqual(result, -2);
    });
  });

  describe('multiply', () => {
    it('should return the product of two numbers', () => {
      const result = multiply(2, 3);
      assert.strictEqual(result, 6);
    });

    it('should return zero if either number is zero', () => {
      const result1 = multiply(2, 0);
      const result2 = multiply(0, 3);
      assert.strictEqual(result1, 0);
      assert.strictEqual(result2, 0);
    });
  });

  describe('divide', () => {
    it('should return the quotient of two numbers', () => {
      const result = divide(6, 3);
      assert.strictEqual(result, 2);
    });

    it('should throw an error if attempting to divide by zero', () => {
      assert.throws(() => divide(6, 0), Error);
    });
  });

});

describe('Sinon demo', function() {
  it('should call the callback function', function() {
    var callback = sinon.spy();

    myFunction(true, callback);

    assert(callback.calledOnce);
  });
});

function add(a, b) {
  return a + b;
}

function subtract(a, b) {
  return a - b;
}

function multiply(a, b) {
  return a * b;
}

function divide(a, b) {
  if (b === 0) {
    throw new Error('Cannot divide by zero');
  }
  return a / b;
}

function myFunction(condition, callback){
  if(condition){
    callback();
  }
}
